1	use anyhow::{bail, Context, Result};
2	use serde::Deserialize;
3	use std::process::Command;
4	
5	use crate::config::{GithubConfig, Scope};
6	
7	/// All GitHub API access goes through the `gh` CLI so we inherit its auth
8	/// (keyring/oauth) instead of handling tokens ourselves. v1 requirement:
9	/// `gh auth login` must have been run for the target.
10	fn api_base(gh: &GithubConfig) -> String {
11	    match gh.scope {
12	        Scope::Repo => format!("repos/{}", gh.target),
13	        Scope::Org => format!("orgs/{}", gh.target),
14	    }
15	}
16	
17	#[derive(Debug, Deserialize)]
18	struct JitConfigResponse {
19	    encoded_jit_config: String,
20	    runner: JitRunner,
21	}
22	
23	#[derive(Debug, Deserialize)]
24	struct JitRunner {
25	    id: u64,
26	    name: String,
27	}
28	
29	/// Ask GitHub for a just-in-time runner registration. A JIT runner accepts
30	/// exactly one job and then deregisters itself — ephemeral by construction,
31	/// no registration token to store or clean up.
32	pub fn generate_jitconfig(
33	    gh: &GithubConfig,
34	    name: &str,
35	    labels: &[String],
36	) -> Result<(String, u64)> {
37	    let path = format!("{}/actions/runners/generate-jitconfig", api_base(gh));
38	    let mut cmd = Command::new("gh");
39	    cmd.args(["api", "-X", "POST", &path, "-f", &format!("name={name}")]);
40	    cmd.args(["-F", "runner_group_id=1"]);
41	    for label in labels {
42	        cmd.args(["-f", &format!("labels[]={label}")]);
43	    }
44	    let out = cmd
45	        .output()
46	        .context("failed to run `gh api` — is the gh CLI installed?")?;
47	    if !out.status.success() {
48	        bail!(
49	            "gh api generate-jitconfig failed for {}: {}",
50	            gh.target,
51	            String::from_utf8_lossy(&out.stderr)
52	        );
53	    }
54	    let parsed: JitConfigResponse =
55	        serde_json::from_slice(&out.stdout).context("unexpected generate-jitconfig response")?;
56	    let _ = parsed.runner.name;
57	    Ok((parsed.encoded_jit_config, parsed.runner.id))
58	}
59	
60	#[derive(Debug, Deserialize)]
61	pub struct RunnerInfo {
62	    pub id: u64,
63	    pub name: String,
64	    pub status: String,
65	    pub busy: bool,
66	}
67	
68	#[derive(Debug, Deserialize)]
69	struct RunnerList {
70	    runners: Vec<RunnerInfo>,
71	}
72	
73	pub fn list_runners(gh: &GithubConfig) -> Result<Vec<RunnerInfo>> {
74	    let path = format!("{}/actions/runners?per_page=100", api_base(gh));
75	    let out = Command::new("gh")
76	        .args(["api", &path])
77	        .output()
78	        .context("failed to run `gh api`")?;
79	    if !out.status.success() {
80	        bail!(
81	            "gh api list runners failed: {}",
82	            String::from_utf8_lossy(&out.stderr)
83	        );
84	    }
85	    let parsed: RunnerList = serde_json::from_slice(&out.stdout)?;
86	    Ok(parsed.runners)
87	}
88	
89	/// Best-effort removal of a registered runner (used when we kill a runner
90	/// container before it ever picked up a job).
91	pub fn remove_runner(gh: &GithubConfig, id: u64) -> Result<()> {
92	    let path = format!("{}/actions/runners/{id}", api_base(gh));
93	    let out = Command::new("gh")
94	        .args(["api", "-X", "DELETE", &path])
95	        .output()
96	        .context("failed to run `gh api`")?;
97	    if !out.status.success() {
98	        bail!(
99	            "gh api remove runner {id} failed: {}",
100	            String::from_utf8_lossy(&out.stderr)
101	        );
102	    }
103	    Ok(())
104	}
105	
106	pub fn gh_auth_ok() -> bool {
107	    Command::new("gh")
108	        .args(["auth", "status"])
109	        .output()
110	        .map(|o| o.status.success())
111	        .unwrap_or(false)
112	}
